// === TEST CASES ===
// TC1: basic 10x12 room, 1 door, 2 windows, 2 coats flat → output { total: 2, breakdown: { wallArea:352, doorsArea:21, windowsArea:30, netArea:301, coats:2, coveragePerGallon:350, gallonsRaw:1.72, gallonsNeeded:2 } }
// TC2: large 20x15 room, 9ft ceiling, 2 doors, 3 windows, 3 coats satin → output { total: 5, breakdown: { wallArea:630, doorsArea:42, windowsArea:45, netArea:543, coats:3, coveragePerGallon:350, gallonsRaw:4.65, gallonsNeeded:5 } }
// TC3: small 8x8 room, 8ft ceiling, 0 doors, 1 window, 1 coat high_gloss → output { total: 1, breakdown: { wallArea:256, doorsArea:0, windowsArea:15, netArea:241, coats:1, coveragePerGallon:300, gallonsRaw:0.8, gallonsNeeded:1 } }
// TC4: no doors/windows 10x10, 1 coat flat → output { total: 1, breakdown: { wallArea:320, doorsArea:0, windowsArea:0, netArea:320, coats:1, coveragePerGallon:350, gallonsRaw:0.91, gallonsNeeded:1 } }
// TC5: negative roomWidth → output { error: "Room width must be greater than 0" }
// TC6: roomWidth NaN or string "abc" → output { error: "Room width must be a number" }
// TC7: missing required fields → output { error: "Room width must be a number" } (catch first missing)
// TC8: invalid paintType "latex" → output { error: "Invalid paint type" }
// TC9: invalid coats "five" → output { error: "Invalid number of coats" }
// TC10: ceilingHeight zero → output { error: "Ceiling height must be greater than 0" }
// TC11: doors negative → output { error: "Doors must be a non‑negative integer" }
// TC12: many doors/windows causing negative net area → output { total: 0, breakdown: { wallArea:320, doorsArea:630, windowsArea:600, netArea:0, coats:1, coveragePerGallon:350, gallonsRaw:0, gallonsNeeded:0 } } (10x10 room, 30 doors, 40 windows)
// TC13: paintType "Satin" (capital S) → treated as satin → output like TC2 with different dims (10x10, 8ft, 0 doors, 0 windows, 1 coat) → { total: 1, breakdown: { wallArea:320, doorsArea:0, windowsArea:0, netArea:320, coats:1, coveragePerGallon:350, gallonsRaw:0.91, gallonsNeeded:1 } }
// TC14: coats "Two" (capital T) → normalizes to "two" → 2 coats → output as if 2 coats on 10x10 flat → { total: 2, breakdown: { wallArea:320, doorsArea:0, windowsArea:0, netArea:320, coats:2, coveragePerGallon:350, gallonsRaw:1.83, gallonsNeeded:2 } }
// TC15: roomWidth string "12" → converted to number 12 → output valid calculation (12x10, 8ft, 0 doors, 0 windows, 1 coat flat) → { total: 1, breakdown: { wallArea:352, doorsArea:0, windowsArea:0, netArea:352, coats:1, coveragePerGallon:350, gallonsRaw:1.01, gallonsNeeded:2 } } (352/350=1.0057 ceil 2) actually 352*1/350=1.0057 ceil=2. So total:2.
// TC16: extremely large room 100x100, 20ft ceiling, 0 doors/windows, 1 coat flat → output { total: 23, breakdown: { wallArea:8000, doorsArea:0, windowsArea:0, netArea:8000, coats:1, coveragePerGallon:350, gallonsRaw:22.86, gallonsNeeded:23 } }
// TC17: 10x10, 30 doors, 40 windows, netArea 0 → output { total: 0, breakdown: { wallArea:320, doorsArea:630, windowsArea:600, netArea:0, coats:1, coveragePerGallon:350, gallonsRaw:0, gallonsNeeded:0 } }
// TC18: roomWidth 0 → output { error: "Room width must be greater than 0" }
// TC19: roomLength 0 → output { error: "Room length must be greater than 0" }
// TC20: omit ceilingHeight (default 8) → output with default: 10x12, 1 door, 2 windows, 2 coats eggshell → output { total: 3, breakdown: { wallArea:352, doorsArea:21, windowsArea:30, netArea:301, coats:2, coveragePerGallon:300, gallonsRaw:2.01, gallonsNeeded:3 } }
// TC21: valid high_gloss paint type → output as TC3

const calculator = {
  COVERAGE: {
    flat: 350,
    eggshell: 300,
    satin: 350,
    semi_gloss: 250,
    high_gloss: 300
  },
  COATS_MAP: { one: 1, two: 2, three: 3 },
  DOOR_AREA: 21,
  WINDOW_AREA: 15,

  validate(inputs) {
    const errors = [];
    // required fields presence and type
    const width = inputs.roomWidth;
    const length = inputs.roomLength;
    const height = inputs.ceilingHeight !== undefined ? inputs.ceilingHeight : 8;
    const doors = inputs.doors;
    const windows = inputs.windows;
    const coats = inputs.coats;
    const paintType = inputs.paintType;

    // roomWidth validation
    if (width === undefined || width === null || width === '') {
      errors.push('Room width must be a number');
    } else {
      const wNum = Number(width);
      if (isNaN(wNum) || !isFinite(wNum)) {
        errors.push('Room width must be a number');
      } else if (wNum <= 0) {
        errors.push('Room width must be greater than 0');
      }
    }

    // roomLength validation
    if (length === undefined || length === null || length === '') {
      errors.push('Room length must be a number');
    } else {
      const lNum = Number(length);
      if (isNaN(lNum) || !isFinite(lNum)) {
        errors.push('Room length must be a number');
      } else if (lNum <= 0) {
        errors.push('Room length must be greater than 0');
      }
    }

    // ceilingHeight validation
    if (height !== undefined && height !== null) {
      const hNum = Number(height);
      if (isNaN(hNum) || !isFinite(hNum)) {
        errors.push('Ceiling height must be a number');
      } else if (hNum <= 0) {
        errors.push('Ceiling height must be greater than 0');
      }
    } else {
      // default will be applied later, no error
    }

    // doors validation (0 or positive integer)
    if (doors !== undefined && doors !== null && doors !== '') {
      const dNum = Number(doors);
      if (isNaN(dNum) || !isFinite(dNum) || Math.floor(dNum) !== dNum || dNum < 0) {
        errors.push('Doors must be a non‑negative integer');
      }
    } else {
      // if not provided, default 0, no error
    }

    // windows validation
    if (windows !== undefined && windows !== null && windows !== '') {
      const wNum = Number(windows);
      if (isNaN(wNum) || !isFinite(wNum) || Math.floor(wNum) !== wNum || wNum < 0) {
        errors.push('Windows must be a non‑negative integer');
      }
    }

    // coats validation (must be one of the keys in COATS_MAP)
    if (coats === undefined || coats === null || coats === '') {
      errors.push('Number of coats is required');
    } else {
      const coatStr = String(coats).toLowerCase().trim();
      if (!this.COATS_MAP.hasOwnProperty(coatStr)) {
        errors.push('Invalid number of coats');
      }
    }

    // paintType validation
    if (paintType === undefined || paintType === null || paintType === '') {
      errors.push('Paint type is required');
    } else {
      const paintStr = String(paintType).toLowerCase().trim();
      if (!this.COVERAGE.hasOwnProperty(paintStr)) {
        errors.push('Invalid paint type');
      }
    }

    return errors;
  },

  calculate(inputs) {
    // First validate
    const validationErrors = this.validate(inputs);
    if (validationErrors.length > 0) {
      return { error: validationErrors[0] };
    }

    // Extract and normalize values
    const width = Number(inputs.roomWidth);
    const length = Number(inputs.roomLength);
    const height = inputs.ceilingHeight !== undefined ? Number(inputs.ceilingHeight) : 8;
    const doors = inputs.doors !== undefined ? Math.floor(Number(inputs.doors)) : 0;
    const windows = inputs.windows !== undefined ? Math.floor(Number(inputs.windows)) : 0;
    const coatsStr = String(inputs.coats).toLowerCase().trim();
    const paintStr = String(inputs.paintType).toLowerCase().trim();

    const coatsNum = this.COATS_MAP[coatsStr];
    const coverage = this.COVERAGE[paintStr];

    // Compute areas
    const wallArea = 2 * (width + length) * height;
    const doorsArea = doors * this.DOOR_AREA;
    const windowsArea = windows * this.WINDOW_AREA;
    let netArea = wallArea - doorsArea - windowsArea;
    if (netArea < 0) netArea = 0;

    // Gallons calculation
    const gallonsRaw = (netArea * coatsNum) / coverage;
    const gallonsNeeded = Math.ceil(gallonsRaw);

    // Round gallonsRaw to 2 decimals for display
    const roundedRaw = parseFloat(gallonsRaw.toFixed(2));

    return {
      total: gallonsNeeded,
      breakdown: {
        wallArea,
        doorsArea,
        windowsArea,
        netArea,
        coats: coatsNum,
        coveragePerGallon: coverage,
        gallonsRaw: roundedRaw,
        gallonsNeeded
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  { name: 'roomWidth', label: 'Room Width (ft)', type: 'number', placeholder: 'e.g. 12' },
  { name: 'roomLength', label: 'Room Length (ft)', type: 'number', placeholder: 'e.g. 10' },
  { name: 'ceilingHeight', label: 'Ceiling Height (ft)', type: 'number', placeholder: '8', default: 8 },
  { name: 'doors', label: 'Number of Doors', type: 'number', placeholder: '0' },
  { name: 'windows', label: 'Number of Windows', type: 'number', placeholder: '0' },
  {
    name: 'coats',
    label: 'Number of Coats',
    type: 'select',
    options: [
      ['one', '1 Coat'],
      ['two', '2 Coats'],
      ['three', '3 Coats']
    ]
  },
  {
    name: 'paintType',
    label: 'Paint Type',
    type: 'select',
    options: [
      ['flat', 'Flat'],
      ['eggshell', 'Eggshell'],
      ['satin', 'Satin'],
      ['semi_gloss', 'Semi-Gloss'],
      ['high_gloss', 'High Gloss']
    ]
  }
];
